const { CosmosClient } = require("@azure/cosmos");
const { app, timerTrigger } = require("@azure/functions");

const cosmosClient = new CosmosClient(process.env.COSMOS_DB_CONNECTION_STRING);
const database = cosmosClient.database(process.env.COSMOS_DB_NAME);
const container = database.container(process.env.COSMOS_DB_CONTAINER);

app.timerTrigger("batchProcessor", {
    schedule: "0 */5 * * * *",
    handler: async function (context, myTimer) {
        const startTime = new Date();
        context.log(`Batch processing started at: ${startTime.toISOString()}`);
        
        try {
            // Disable timeout enforcement for Consumption plan
            context.executionContext.setCustomContext({
                timeout: 600000 // 10 minutes in milliseconds
            });
            
            const query = {
                query: "SELECT * FROM c WHERE c.processed = false",
                parameters: []
            };
            
            const maxItems = 1000;
            let continuationToken = null;
            let processedCount = 0;
            
            do {
                const options = {
                    maxItemCount: maxItems,
                    continuation: continuationToken
                };
                
                const { resources, headers } = await container.items.query(query, options).fetchAll();
                
                if (resources.length > 0) {
                    // Process batch
                    const batchResults = await processBatch(resources);
                    processedCount += resources.length;
                    
                    context.log(`Processed batch of ${resources.length} items. Total processed: ${processedCount}`);
                }
                
                continuationToken = headers["x-ms-continuation"];
                
                // Check if we're approaching timeout (5 minutes remaining)
                const elapsed = Date.now() - startTime.getTime();
                if (elapsed > 5 * 60 * 1000) {
                    context.log("Approaching timeout, will continue processing in next execution");
                    break;
                }
                
            } while (continuationToken);
            
            context.log(`Batch processing completed. Total items processed: ${processedCount}`);
            
        } catch (error) {
            context.log.error(`Error in batch processing: ${error.message}`);
            throw error;
        }
    }
});

async function processBatch(items) {
    const batchOperations = [];
    
    for (const item of items) {
        try {
            // Process individual item
            const processedItem = await processItem(item);
            
            // Prepare batch operation
            batchOperations.push({
                operationType: "Replace",
                resourceBody: processedItem
            });
            
        } catch (error) {
            // Log error but continue with other items
            console.error(`Error processing item ${item.id}: ${error.message}`);
        }
    }
    
    // Execute batch operations
    if (batchOperations.length > 0) {
        await container.items.batch(batchOperations);
    }
    
    return batchOperations.length;
}

async function processItem(item) {
    // Add your data processing logic here
    // Example: item.processed = true;
    // Example: item.processedAt = new Date().toISOString();
    
    return {
        ...item,
        processed: true,
        processedAt: new Date().toISOString()
    };
}

